-- HERPA quiz seed for current Supabase schema (min 10 unique questions per level).
-- Uses quiz_subjects, quiz_modules, quiz_levels, quiz_questions, quiz_question_options.
-- Safe to rerun: questions are inserted only when same prompt does not exist for the level.

insert into public.quiz_subjects(slug,title,description,sort_order,is_active) values ('kimia-medbot','Kuis Kimia MedBot AI','Micro-learning kimia dan herbal.',1,true) on conflict (slug) do update set title=excluded.title, description=excluded.description, sort_order=excluded.sort_order, is_active=true;
insert into public.quiz_modules(subject_id,slug,title,description,sort_order,is_active) select s.id, 'struktur-atom','Struktur Atom','Kuis bertingkat untuk Struktur Atom.',1,true from public.quiz_subjects s where s.slug='kimia-medbot' on conflict (slug) do update set title=excluded.title, description=excluded.description, sort_order=excluded.sort_order, is_active=true;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 1,'Level 1',70,20,'multiple_choice',1 from public.quiz_modules m where m.slug='struktur-atom' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 2,'Level 2',70,20,'matching',2 from public.quiz_modules m where m.slug='struktur-atom' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 3,'Level 3',70,20,'true_false',3 from public.quiz_modules m where m.slug='struktur-atom' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 4,'Level 4',70,20,'short_answer',4 from public.quiz_modules m where m.slug='struktur-atom' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 5,'Level 5',70,20,'case_based',5 from public.quiz_modules m where m.slug='struktur-atom' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
with lvl as (select l.id from public.quiz_levels l join public.quiz_modules m on m.id=l.module_id where m.slug='struktur-atom' and l.level_number=1),
ins as (insert into public.quiz_questions(level_id,question_type,prompt,explanation,correct_answer,accepted_answers,matching_pairs,difficulty,metadata,is_active,order_index,xp_reward,options) select lvl.id, 'multiple_choice','Partikel subatom bermuatan positif adalah...','Proton bermuatan positif.','"A"'::jsonb,'[]'::jsonb,'[]'::jsonb,'easy','{"order_index": 1}'::jsonb,true,1,10,'[{"id": "A", "label": "A", "text": "proton"}, {"id": "B", "label": "B", "text": "neutron"}, {"id": "C", "label": "C", "text": "elektron"}, {"id": "D", "label": "D", "text": "isotop"}]'::jsonb from lvl where not exists (select 1 from public.quiz_questions q where q.level_id=lvl.id and lower(trim(q.prompt))=lower(trim('Partikel subatom bermuatan positif adalah...'))) returning id) 
insert into public.quiz_question_options(question_id,option_key,label,is_correct,sort_order) select * from (values (ins.id,'A','proton',true,0),(ins.id,'B','neutron',false,1),(ins.id,'C','elektron',false,2),(ins.id,'D','isotop',false,3)) as v(question_id,option_key,label,is_correct,sort_order), ins;
