insert into public.quiz_modules(subject_id,slug,title,description,sort_order,is_active) select s.id, 'asam-basa','Asam Basa','Kuis bertingkat untuk Asam Basa.',6,true from public.quiz_subjects s where s.slug='kimia-medbot' on conflict (slug) do update set title=excluded.title, description=excluded.description, sort_order=excluded.sort_order, is_active=true;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 1,'Level 1',70,20,'multiple_choice',1 from public.quiz_modules m where m.slug='asam-basa' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 2,'Level 2',70,20,'matching',2 from public.quiz_modules m where m.slug='asam-basa' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
insert into public.quiz_levels(module_id,level_number,title,passing_score,xp_reward,quiz_type,order_index) select m.id, 3,'Level 3',70,20,'true_false',3 from public.quiz_modules m where m.slug='asam-basa' on conflict (module_id,level_number) do update set title=excluded.title, passing_score=excluded.passing_score, xp_reward=excluded.xp_reward, quiz_type=excluded.quiz_type, order_index=excluded.order_index;
